using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class MealLogConfiguration : IEntityTypeConfiguration<MealLog>{public void Configure(EntityTypeBuilder<MealLog> builder){builder.ToTable("meal_logs");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("log_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Status).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.ActualPortion).HasColumnType("decimal(4,2)");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.PlanMeal).WithMany().HasForeignKey(e => e.PlanMealId);builder.HasOne(e => e.Recipe).WithMany().HasForeignKey(e => e.RecipeId);builder.HasIndex(e => new { e.UserId, e.LoggedForDate });}}
